public sealed class SwedenSalesTaxStrategy : ISalesTaxStrategy
{
    public decimal GetTaxFor(Order order)
    {
        decimal totalTax = 0m;

        foreach (var item in order.LineItems)
        {
            decimal rate = item.Type switch
            {
                ItemType.Food => 0.06m,
                ItemType.Literature => 0.08m,
                ItemType.Service => 0.25m,
                ItemType.Hardware => 0.25m,
                _ => 0m
            };

            totalTax += item.Price * rate;
        }

        return totalTax;
    }
}

public enum ItemType
{
    Food,
    Literature,
    Service,
    Hardware
}

public decimal GetTax(ISalesTaxStrategy? strategy = null)
