    if (effectiveStrategy is null)
    {
        return 0m;
    }

    return effectiveStrategy.GetTaxFor(this);
}

public interface IInvoiceStrategy
{
    void Generate(Order order);
}

public abstract class InvoiceStrategy : IInvoiceStrategy
{
    public abstract void Generate(Order order);

    protected string GenerateTextInvoice(Order order)
    {
        var lines = new List<string>
        {
            $"Invoice date: {DateTime.UtcNow:yyyy-MM-dd}",
            "Items:"
        };

        foreach (var item in order.LineItems)
        {
            lines.Add($"- {item.Name}: {item.Price:C}");
        }

        lines.Add($"Tax: {order.GetTax():C}");
        lines.Add($"Total: {order.LineItems.Sum(x => x.Price) + order.GetTax():C}");

        return string.Join(Environment.NewLine, lines);
    }
}

public sealed class EmailInvoiceStrategy : InvoiceStrategy
{
    public override void Generate(Order order)
    {
        var body = GenerateTextInvoice(order);
